  {#if !status.started}
    <section class="boot"><p class="code">G&K TACTICAL COMMAND NETWORK</p><h2>소녀전선: 잔불</h2><p>원본 카드의 설정과 이미지를 Lucky 결정론 엔진으로 변환했습니다. 게임 수치는 엔진이 확정하고 AI는 장면과 대사를 연출합니다. 원본에서 회수한 값과 Lucky가 보정한 규칙의 목록은 진단 콘솔에서 확인할 수 있습니다.</p><div><button onclick={()=>act('gfl/start',{mode:'commander'})}>지휘관으로 시작</button><button onclick={()=>act('gfl/start',{mode:'doll'})}>전술인형으로 시작</button></div></section>
  {:else}
    <nav>{#each [['base','기지'],['hire','인형 고용'],['dolls','인형'],['echelon','제대'],['operation','작전'],['factory','제조·수복'],['shop','상점·장비']] as item}<button class:active={tab===item[0]} disabled={item[0]==='factory'&&(locations.currentId!=='base-maintenance'||locations.locked)} onclick={()=>openTab(item[0]as typeof tab)}>{item[1]}</button>{/each}</nav>
    <div class="location-bar"><span>현재 위치 · <b>{String((status.effectiveLocation as Row)?.name??status.locationName??'지휘관실')}</b></span><div>{#each locations.locations.filter(location=>location.reachable) as location}<button class:active={Boolean(location.current)} disabled={Boolean(location.current)||locations.locked||Boolean(dialogueState)} onclick={()=>act('gfl/location/move',{locationId:location.id},'narrated')}>{String(location.name)}</button>{/each}<button class="time-advance" disabled={!canAdvance} title={String(status.phase)==='새벽'?'새벽에는 하루 마감으로 다음 날을 정산하세요.':''} onclick={()=>act('gfl/time/advance',{},'narrated')}>다음 시간대</button><button class="time-advance" disabled={!canEndDay} title={!canEndDay?'하루 마감은 저녁 이후에 가능합니다.':''} onclick={()=>act('gfl/time/end-day',{},'narrated')}>하루 마감</button></div></div>
    <div class="workspace">
      {#if tab==='base'}
        <section class="stage">{#if activeDoll}{@const image=portrait(String(activeDoll.id))}{#if image}<img src={image} alt={String(activeDoll.name)}/>{/if}{/if}<div class="scan"></div><div class="name">{String(activeDoll?.name??'KALINA')}</div></section>
        <section class="dialogue"><span>GRIFFIN BASE / {String(status.locationName??'지휘관실')}</span><p>{message}</p><section class="daily-card"><h3>오늘의 임무 · {daily.completed}/4</h3>{#each daily.tasks as task}<div><span>{Number(task.progress) >= Number(task.target)?'✓':'○'} {String(task.label)}</span><b>{String(task.progress)}/{String(task.target)}</b></div>{/each}<small>2개 완료: 자금 300·자원 150 / 전부 완료: 자금 700·자원 350</small></section><section class="diss-card"><h3>기지 불만도 · {String(diss.value??0)} <small>{String(diss.label??'')}</small></h3><progress class:diss-high={Number(diss.value??0)>=50} value={Number(diss.value??0)} max={100}></progress><small>{String(diss.text??'')}</small></section><section class="crew-card"><h3>시설 근무 <small>기분을 쓰는 인형이 시설을 움직입니다 · 숙소에서 쉬면 회복</small></h3>{#each crewRows as station}<article class:slacked={station.slacked===true}><div><b>{String(facilities.find(f=>f.id===station.facilityId)?.name??station.facilityId)}</b><small>{String(station.effectLabel)} · 적성 {(station.aptitude as string[]).join('·')}{station.slacked?' · 오늘 태만!':''}</small><small>{#each (station.workers as Row[]) as worker}<button class="crew-chip" title="근무 해제" onclick={()=>act('gfl/crew/remove',{facilityId:station.facilityId,dollId:worker.dollId})}>{String(worker.name)}{worker.aptitude?'★':''} 기분{String(worker.mood)} ✕</button>{/each}</small></div><select onchange={(event)=>{const value=(event.currentTarget as HTMLSelectElement).value;if(value){void act('gfl/crew/assign',{facilityId:station.facilityId,dollId:value});(event.currentTarget as HTMLSelectElement).value='';}}}><option value="">근무 배치…</option>{#each dolls.filter(unit=>!crewedIds.has(String(unit.id))&&unit.status==='대기') as unit}<option value={String(unit.id)}>{String(unit.name)} · {String(unit.class)}{(station.aptitude as string[]).includes(String(unit.class))?' ★적성':''}</option>{/each}</select></article>{/each}</section><section class="refinery-card"><h3>가공 라인 <small>슬롯 {refinery.jobs.filter(job=>job.status==='active').length}/{refinery.slots}</small></h3><div class="factory-actions">{#each refinery.recipes as recipe}<button onclick={()=>act('gfl/refinery/start',{recipe:recipe.id})}>{String(recipe.label)} <small>{Object.entries(recipe.cost as Row).map(([key,amount])=>`${key} ${amount}`).join('·')} → {Object.entries(recipe.yield as Row).map(([key,amount])=>`${key} ${amount}`).join('·')} · {String(recipe.duration)}시간대</small></button>{/each}</div>{#each refinery.jobs as job}<article><span>{String(job.label)} · {String(job.status)}</span><b>{String(job.remaining)}단계</b>{#if job.status==='complete'}<button onclick={()=>act('gfl/refinery/collect',{jobId:job.id})}>수령</button>{/if}</article>{/each}</section><div class="facility-grid">{#each facilities as facility}<article class:expanded={facilityExpanded===facility.id}><button class="facility-summary" aria-expanded={facilityExpanded===facility.id} onclick={()=>facilityExpanded=facilityExpanded===facility.id?'':String(facility.id)}><b>{String(facility.name)}</b><small>Lv.{String(facility.level)}</small><span>{facility.cost?'증설 가능':'최고 레벨'}</span></button>{#if facilityExpanded===facility.id}<div class="facility-detail"><b>현재 효과</b>{#each effectLines(facility.currentEffect) as line}<small>{line}</small>{/each}{#if cost(facility.cost)}<b>다음 효과</b>{#each effectLines(facility.nextEffect) as line}<small>{line}</small>{/each}<small>증설비 · 자금 {Number(cost(facility.cost)?.gold??0).toLocaleString()} / 자원 {Number(cost(facility.cost)?.res??0).toLocaleString()}</small><button onclick={()=>act('gfl/facility/upgrade',{facilityId:facility.id})}>시설 증설</button>{/if}{#if facility.specialization}<small>특화 완료 · {String(facility.specialization)}</small>{/if}{#if Array.isArray(facility.branches)&&(facility.branches as Row[]).length}<b>특화 선택 · 되돌릴 수 없음</b>{#each facility.branches as Row[] as branch}<button onclick={()=>act('gfl/facility/specialize',{facilityId:facility.id,branch:branch.id})}>{String(branch.label)} <small>{String(branch.desc)}</small></button>{/each}{/if}</div>{/if}</article>{/each}</div></section>
        <section class="archive"><details><summary>기록실 · {archive.unlockedCount}/{archive.documents.length} · 완료 작전 {archive.completed}회</summary><div>{#each archive.documents as document}{#if document.unlocked}<details><summary>{String(document.year)} · {String(document.code)} · {String(document.title)}</summary>{#each effectLines(document.body) as line}<p>{line}</p>{/each}</details>{:else}<article class="locked"><b>───</b><span>작전 기록 잠금</span></article>{/if}{/each}</div></details></section>
      {:else if tab==='hire'}
        <section class="list"><div class="hire-head"><div><h2>전술인형 고용</h2><p>숙소 {hire.count}/{hire.capacity} · 매일 무작위 명단 · 하루 한 명 계약</p><small>같은 날 한 번 더 주사위를 굴릴 수 있으며, 계약한 인형은 다음 시간대에 도착합니다.</small></div><button disabled={!hire.canRefresh&&hire.offers.length>0} onclick={()=>act('gfl/hire/refresh')}>{hire.offers.length?'🎲 목록 다시 뽑기 · 오늘 1회':'🎲 오늘의 인형 뽑기'}</button></div><div class="hire-grid">{#each hire.offers as offer}{@const image=portrait(String(offer.id))}<article><span class="portrait">{#if image}<img src={image} alt=""/>{:else}<span class="portrait-loading" aria-label={`${String(offer.name)} 이미지 불러오는 중`}>불러오는 중</span>{/if}</span><div><b>{String(offer.name)}</b><small>{String(offer.class)} · ★{String(offer.grade)}</small><p>{String(offer.description??'')}</p></div><strong>{Number(offer.price??0).toLocaleString()} 자금</strong><button disabled={hire.hiredToday||hire.count>=hire.capacity} onclick={()=>act('gfl/hire/contract',{dollId:offer.id})}>계약</button></article>{/each}</div><h3>저격 고용</h3><DollPicker rows={hire.available} priceKey="snipePrice" pickLabel="지정 계약" {portraitFor} onpick={(id)=>act('gfl/hire/snipe',{dollId:id})}/>{#if hire.arrivals.length}<button onclick={()=>act('gfl/time/advance',{},'narrated')}>다음 시간대 · 수송 도착</button>{/if}</section>
      {:else if tab==='dolls'}
        {#if activeDoll}<section class="dismantle"><b>{String(activeDoll.name)} 해체</b><span>코어 1개와 자원 500~2,000을 회수합니다.</span><button onclick={()=>{if(confirm(`전술인형 ${String(activeDoll?.name)}을(를) 해체하시겠습니까? 되돌릴 수 없습니다.`))act('gfl/doll/dismiss',{dollId:activeDoll?.id,confirm:true},'narrated')}}>인형 해체 · 확인 필요</button></section>{/if}
        <section class="list"><h2>전술인형 관리</h2><DollPicker rows={dolls} pickLabel="선택" {portraitFor} onpick={(id)=>selectedDoll=id}/></section>
        {#if activeDoll&&(status.promiseRequest as Row)?.dollId===activeDoll.id}<section class="promise-request"><b>{String(activeDoll.name)}의 약속 요청</b><span>{(status.promiseRequest as Row).type==='sortie'?'다음 작전에 데려가 주세요':(status.promiseRequest as Row).type==='repair'?'수복을 미루지 말아 주세요':'기념일에 시간을 내주세요'}</span><div><button onclick={()=>act('gfl/relation/promise/accept',{},'narrated')}>약속한다</button><button onclick={()=>act('gfl/relation/promise/decline',{})}>지금은 어렵다</button></div></section>{/if}
        {#if activeDoll}<aside class="detail"><h3>{String(activeDoll.name)}{#if activeDoll.callsign} · “{String(activeDoll.callsign)}”{/if}</h3><p>{String(activeDoll.class)} / ★{String(activeDoll.grade)}</p><label>HP {String(hp(activeDoll.hp).cur??0)} / {String(hp(activeDoll.hp).max??0)}<progress value={hp(activeDoll.hp).cur??0} max={hp(activeDoll.hp).max??1}></progress></label><p>기분 {String(activeDoll.mood)} · 호감도 {String(activeDoll.affinity)} · MOD {String(activeDoll.mod)}{#if activeDoll.refusal===true} · <b class="refusal-badge">항명 중</b>{/if}{#if crewedIds.has(String(activeDoll.id))} · 근무 중{/if}{#if activeDoll.squad} · {String(activeDoll.squad)} 소대{/if}</p><section class="romance-facts"><span>취향 · <b>{String(activeRelation?.preferenceHint??'?')}</b></span>{#if activeDoll.secretHobby}<span>비밀 취미 · <b>{String(activeDoll.secretHobby)}</b></span>{/if}{#if activeDoll.trauma}<span>트라우마 · <b>{String(activeDoll.trauma)} ({String(activeDoll.traumaProgress??0)}/3)</b></span>{/if}{#if activeDoll.overcomeMedal}<span>극복 훈장 · <b>{String(activeDoll.overcomeMedal)} 명중 +1</b></span>{/if}</section><button class:active={status.featuredDollId===activeDoll.id} onclick={()=>act('gfl/doll/feature',{dollId:activeDoll.id})}>{status.featuredDollId===activeDoll.id?'기지 대표 인형':'기지 대표로 설정'}</button><h4>관계 선택지 · d20 판정</h4>{#if activeRelation}<p class="relation-meta">{String((activeRelation.tier as Row)?.label??'첫 만남')} · 오늘 교류 {String(activeRelation.remaining??0)}회 남음</p>{/if}<div class="choice-capsules">{#each (Array.isArray(activeRelation?.choices)?activeRelation.choices as Row[]:[]) as option (option.id)}<button disabled={!option.available} title={option.available?'':lockText(option)} onclick={()=>act('gfl/relation/check',{dollId:activeDoll.id,choice:option.id},'narrated')}>{String(option.label)} <small>{option.available?`DC ${String(option.dc)}${Number(option.used)>0?' · 효과 절반':''}`:lockText(option)}</small></button>{/each}</div>{#if dialogueState&&String(dialogueState.dollId)===String(activeDoll.id)}{#if activeDoll.trauma}<button class="trauma-action" onclick={()=>act('gfl/relation/heal-trauma',{dollId:activeDoll.id},'narrated')}>심리 치유 · 현재 {String(activeDoll.traumaProgress??0)}/3</button>{/if}<button class="dialogue-toggle" onclick={()=>act('gfl/relation/session/end',{},'narrated')}>🗨 대화를 마무리한다 <small>교감 보너스 확정</small></button>{:else}<button class="dialogue-toggle" disabled={Boolean(dialogueState)||activeRelation?.dialogueUsed===true} title={dialogueState?'다른 인형과 대화 중입니다':activeRelation?.dialogueUsed===true?'오늘은 이미 대화를 마쳤습니다':''} onclick={()=>act('gfl/relation/session/start',{dollId:activeDoll.id},'narrated')}>🗨 1:1 대화 시작 <small>{activeRelation?.dialogueUsed===true?'오늘 완료':'시간 정지'}</small></button>{/if}<button class="outing-action" disabled={!activeRelation?.outingAvailable} title={activeRelation?.outingUsed?'오늘은 이미 함께 외출했습니다':'신뢰 관계·대기 상태에서 가능합니다'} onclick={()=>act('gfl/relation/outing',{dollId:activeDoll.id},'narrated')}>함께 외출 · 시간대 1칸</button>{#if activeRelation?.callsignEligible}<div class="callsign-form"><input maxlength="20" placeholder="호칭을 직접 입력 (20자)" bind:value={callsignDraft}/><button disabled={!callsignDraft.trim()} onclick={()=>{void act('gfl/relation/callsign',{dollId:activeDoll?.id,callsign:callsignDraft.trim()},'narrated');callsignDraft='';}}>호칭 확정</button></div>{/if}{#each (Array.isArray(status.promises)?status.promises as Row[]:[]).filter(value=>value.dollId===activeDoll?.id) as promise}<p class="promise-chip">약속 · {promise.type==='sortie'?'다음 작전 동행':promise.type==='repair'?'부상 시 빠른 수복':'기념일 함께 보내기'} · {promise.deadline?`${String(promise.deadline)}일차까지`:'부상 시 기한 시작'}</p>{/each}{#each (Array.isArray(status.promiseReceipts)?status.promiseReceipts as Row[]:[]).filter(value=>value.dollId===activeDoll?.id) as receipt}<p class="promise-chip">{receipt.fulfilled?'✓ 약속 이행 완료':'✕ 약속 위반'} · 호감 {Number(receipt.affinityDelta)>0?'+':''}{String(receipt.affinityDelta)} · 기분 {Number(receipt.moodDelta)>0?'+':''}{String(receipt.moodDelta)}</p>{/each}<button onclick={()=>act('gfl/repair/start',{dollId:activeDoll.id})}>수복 투입</button><button onclick={()=>act('gfl/mod/upgrade',{dollId:activeDoll.id})}>MOD 개조</button><details class="advanced"><summary>고급 설정 · 관계 난이도 / 소문 / 질투</summary><p>호감도 상승과 하락 폭만 조절하며 판정 주사위는 그대로입니다.</p><div>{#each [['relaxed','느긋함 · 상승 1.5배 / 하락 0.5배'],['standard','기본 · 상승·하락 1배'],['strict','엄격함 · 상승 0.7배 / 하락 1.25배']] as option}<button class:active={(status.settings as Row)?.relationDifficulty===option[0]} onclick={()=>act('gfl/settings/update',{relationDifficulty:option[0]})}>{option[1]}</button>{/each}</div><p>뜬소문 — 불만이 높을 때 기지에 퍼지는 소문의 수위입니다.</p><div>{#each [['off','끔 · 소문 없음'],['mild','순한맛 · 기분만 영향(기본)'],['full','진한맛 · 호감도까지 영향']] as option}<button class:active={(status.settings as Row)?.gossip===option[0]} onclick={()=>act('gfl/settings/update',{gossip:option[0]})}>{option[1]}</button>{/each}</div><p>질투 — 대화·외출에 소외된 인형이 난입할 때의 영향입니다.</p><div>{#each [['off','끔 · 효과 없음'],['mild','순한맛 · 기분만 영향(기본)'],['full','진한맛 · 호감도까지 영향']] as option}<button class:active={(status.settings as Row)?.jealousy===option[0]} onclick={()=>act('gfl/settings/update',{jealousy:option[0]})}>{option[1]}</button>{/each}</div><p>작전 서사 — 빠른 교전에서 자동 진행을 쓸지, 단계마다 장면을 볼지 고릅니다.</p><div>{#each [['auto','자동 진행 · 정지 지점까지 한 번에(기본)'],['each','단계별 · 매 단계 장면을 본다']] as option}<button class:active={(status.settings as Row)?.stageNarration===option[0]} onclick={()=>act('gfl/settings/update',{stageNarration:option[0]})}>{option[1]}</button>{/each}</div></details></aside>{/if}
        {#if activeDoll}<section class="doll-inventory"><h3>{String(activeDoll.name)}에게 사용할 보유 물품</h3>{#each shop.catalog.filter(item=>Number(item.owned??0)>0) as item}<article><div><b>{String(item.name)}</b><small>{String(item.description??'')}</small><small>{effectText(item.effect)} · 보유 {String(item.owned)}</small></div>{#if item.kind==='item'&&item.type==='use'}<button onclick={()=>act('gfl/item/use',{dollId:activeDoll.id,itemId:item.id},'narrated')}>사용</button>{:else if item.kind==='equipment'}<button onclick={()=>act('gfl/equipment/equip',{dollId:activeDoll.id,equipmentId:item.id})}>장착</button>{/if}<button onclick={()=>act('gfl/item/sell',{itemId:item.id})}>판매</button></article>{/each}{#if Array.isArray(activeDoll.equipment)&&activeDoll.equipment.length}<h4>장착 중</h4>{#each activeDoll.equipment as equipmentId}<button onclick={()=>act('gfl/equipment/unequip',{dollId:activeDoll.id,equipmentId})}>{String(shop.catalog.find(item=>item.id===equipmentId)?.name??equipmentId)} 해제</button>{/each}{/if}</section>{/if}
        {#if activeDoll?.oathed}<section class="oath-status"><b>💍 {String(activeDoll.name)}와 서약 완료</b><span>기분은 30 아래로 내려가지 않으며 최종 전투력에 +5%가 적용됩니다.</span></section>{/if}
      {:else if tab==='echelon'}
        <section class="list"><h2>제대 편성</h2><div class="echelon-tabs">{#each echelons as entry}<button class:active={activeEchelon?.id===entry.id} onclick={()=>selectedEchelon=String(entry.id)}>{String(entry.name)} · {String(entry.power)} <small>훈련시설 +{String(entry.trainingBonus??0)}%</small></button>{/each}</div>{#if activeEchelon}<p class="formation-hint">RF·MG는 후열 +38%, SG·SMG는 전열에서 아군을 지킵니다.{#if recommendedRow} · {String(selectedRoster?.name)} 권장: {recommendedRow}{/if}</p><div class="slots">{#each activeSlots as member,index}{@const memberId=slotId(member)}{@const memberDoll=dolls.find(value=>value.id===memberId)}{@const image=memberDoll?portrait(String(memberDoll.id)):null}<div class:recommended={recommendedRow===rowOf(member)} class="slot" data-row={rowOf(member)}><strong>{rowOf(member)}</strong><button class:selected={selectedSlot===index} onclick={()=>selectedSlot=index}>{#if memberDoll&&image}<img src={image} alt=""/>{/if}<span>SLOT {index+1}</span><b>{String(memberDoll?.name??'EMPTY')}</b></button>{#if memberId}<button class="remove" aria-label={`${String(memberDoll?.name??'인형')} 배치 해제`} onclick={()=>act('gfl/echelon/remove',{echelonId:activeEchelon.id,slot:index})}>배치 해제</button>{/if}</div>{/each}</div><h3>배치할 인형</h3><DollPicker compact rows={dolls} pickLabel="배치" {portraitFor} onpick={(id)=>{selectedRosterDoll=id;act('gfl/echelon/assign',{echelonId:activeEchelon.id,slot:selectedSlot,dollId:id});}}/>{/if}</section>
        {#if activeEchelon}<section class="logistics-panel"><h3>군수지원 · {String(activeEchelon.name)}</h3>{#if activeLogistics}{@const reward=activeLogistics.reward as Row}<p>{activeLogistics.status==='complete'?'복귀 완료 · 보급품 수령 대기':`파견 중 · ${String(activeLogistics.remaining)}시간대 남음`} · 자금 {Number(reward?.gold??0).toLocaleString()} / 자원 {Number(reward?.res??0).toLocaleString()}</p>{#if activeLogistics.status==='complete'}<button onclick={()=>act('gfl/logistics/collect',{jobId:activeLogistics.id})}>보급품 수령</button>{/if}{:else}<p>파견 순간 보상이 확정되며, 다른 제대는 계속 작전할 수 있습니다.</p><div>{#each [2,4,6] as duration}<button onclick={()=>act('gfl/logistics/dispatch',{echelonId:activeEchelon.id,duration})}>{duration}시간대 파견</button>{/each}</div>{/if}</section>{/if}
      {:else if tab==='operation'}
        <section class="list"><h2>작전 지도 <small>오늘 {daily.sortiesUsed}/{daily.sortieLimit}회</small></h2>
          {#if ['심야','새벽'].includes(String(status.phase??''))}{@const night=nightModifier(activeEchelon)}<p class="night-warning">🌙 야간전 · 기본 명중 −3{night.hg?` · HG ${night.hg}명 조명 +${night.hg*2}`:''} · 최종 {night.modifier>=0?'+':''}{night.modifier} · 부품 보상 ×2</p>{/if}
          {#if lastBattle?.night&&!sortie}<p class="night-report">🌙 최근 전투는 야간전이었습니다 · 명중 {Number(lastBattle.nightHitModifier)>=0?'+':''}{String(lastBattle.nightHitModifier)} · 부품 보상 ×2</p>{/if}
          {#if lastBattle&&!sortie&&lastBattle.commanderExp}<p class="commander-exp">지휘 EXP +{String((lastBattle.commanderExp as Row).gained)} · 누적 {Number((lastBattle.commanderExp as Row).total??0).toLocaleString()} · Lv {String((lastBattle.commanderExp as Row).level)}</p>{/if}
          {#if lastBattle?.intervention}<p class="command-report">📣 지휘 개입 · {String((lastBattle.intervention as Row).round)}라운드 {String((lastBattle.intervention as Row).type)}</p>{/if}
          {#if lastBattle&&!sortie}<details class="battle-report"><summary>최근 전투 보고 · {lastBattle.outcome==='victory'?'작전 성공':'작전 실패'} · {String(lastBattle.roundCount)}라운드</summary><p>작전 판정: d20 {String((lastBattle.missionCheck as Row)?.roll)} {Number((lastBattle.missionCheck as Row)?.modifier??0)>=0?'+':''}{String((lastBattle.missionCheck as Row)?.modifier)} = {String((lastBattle.missionCheck as Row)?.total)} · {String((lastBattle.missionCheck as Row)?.condition)}</p>{#if lastBattle.factionLabel}<p>상성: {String(lastBattle.factionLabel)}</p>{/if}<div class="combat-roster">{#each (Array.isArray(lastBattle.allies)?lastBattle.allies:[]) as unit}{@const image=portrait(String((unit as Row).id))}<div>{#if image}<img src={image} alt=""/>{/if}<b>{String((unit as Row).name)}</b><span>HP {String((unit as Row).hpBefore)} → {String((unit as Row).hp)} / {String((unit as Row).maxHp)}</span></div>{/each}</div>{#each (Array.isArray(lastBattle.rounds)?lastBattle.rounds:[]).slice(0,battleExpanded?undefined:6) as round}<article><b>{String((round as Row).round)}라운드</b><span class="exchanges">{#each (Array.isArray((round as Row).exchanges)?(round as Row).exchanges as Row[]:[]) as exchange}<i class:critical={Boolean(exchange.critical)} class:counter={Boolean(exchange.counter)} class:miss={!exchange.hit}>{exchange.counter?'⚡ ':''}{String(exchange.actorId)} → {String(exchange.targetId)} {exchange.hit?`피해 ${String(exchange.damage)}`:'빗나감'}</i>{/each}</span></article>{/each}{#if Array.isArray(lastBattle.rounds)&&lastBattle.rounds.length>6}<button class="round-more" onclick={()=>battleExpanded=!battleExpanded}>{battleExpanded?'라운드 접기':'라운드 더 보기'}</button>{/if}<div class="enemy-strip">{#each (Array.isArray(lastBattle.enemies)?lastBattle.enemies:[]) as enemy}<span>{(enemy as Row).boss?'[BOSS] ':''}{String((enemy as Row).name)} · HP {String((enemy as Row).hp)}/{String((enemy as Row).maxHp)}</span>{/each}</div>{#if Array.isArray(lastBattle.loot)&&lastBattle.loot.length}<p class="loot">전리품: {(lastBattle.loot as Row[]).map(item=>`${String(item.name)} ×${String(item.qty)}`).join(' · ')}</p>{/if}<small>같은 작전 반복 클리어 보상은 최초의 35%입니다.</small></details>{/if}
          {#if sortie}
            {@const sortieEchelon=echelons.find(entry=>entry.id===sortie?.echelonId)}
            {@const stages=Array.isArray(sortie.stages)?sortie.stages as Row[]:[]}
            {@const current=Number(sortie.current??0)}
            {@const currentStage=stages[current]??{type:'battle'}}
            {@const combatStage=currentStage.type==='battle'||currentStage.type==='boss'}
            <div class="brief"><b>작전 진행 중 · {String(sortie.missionId)} · {current+1}/{stages.length}</b><span>{sortie.engagementMode==='quick'?'빠른 교전':'전술 교전'} · 제대 {String(sortie.echelonId)} · 전투력 {String(sortie.power)}</span>
              <div class="stage-tracker" aria-label="작전 단계">{#each stages as stage,index}<span class:current={index===current} class:done={Boolean(stage.completed)} title={`${index+1}단계 · ${String(stage.type)}`}>{stage.completed?'✓':String(({battle:'⚔',boss:'👑',recon:'🔍',other:'🚩',mystery:'❓'}as Row)[String(stage.type)]??'·')}</span>{/each}</div>
              <section class="battle-intel"><b>관측 정보 Lv {intel.level} · 지휘 게이지 {String(sortie.command??0)}/100</b>{#if intel.level===0&&intel.estimate}<span>적 {String(intel.estimate.count)}명 · 전투력 추정 {Number(intel.estimate.minPower??0).toLocaleString()}~{Number(intel.estimate.maxPower??0).toLocaleString()}</span>{:else}{#each intel.enemies as enemy}<span>{String(enemy.name)} · {String(enemy.class)}{#if intel.level>=2} · HP {String(enemy.hp)}{/if}</span>{/each}{/if}</section>
              {#if sortie.scouted}<p class="scouted">🔍 정찰 완료 · 다음 교전 명중 +1</p>{/if}
              {#if sortie.encounter&&typeof sortie.encounter==='object'}{@const encounter=sortie.encounter as Row}<div class="field-encounter"><b>무소속 전술인형 『{String(encounter.name??encounter.dollId)}』 발견</b><span>숙소에 자리가 있으면 즉시 합류합니다.</span><div><button onclick={()=>act('gfl/encounter/recruit',{},'narrated')}>영입을 시도한다</button><button onclick={()=>act('gfl/encounter/skip')}>두고 간다</button></div></div>{/if}
              {#if lastBattle&&Array.isArray(lastBattle.loot)&&lastBattle.loot.length}<p class="loot">전리품: {(lastBattle.loot as Row[]).map(item=>`${String(item.name)} ×${String(item.qty)}`).join(' · ')}</p>{/if}
              <div class="combat-roster">{#each (Array.isArray(sortieEchelon?.slots)?sortieEchelon.slots:[]) as member}{@const unit=dolls.find(value=>value.id===slotId(member))}{#if unit}{@const image=portrait(String(unit.id))}{@const health=hp(unit.hp)}<div>{#if image}<img src={image} alt=""/>{/if}<b>{String(unit.name)}</b><progress value={Number(health.cur??0)} max={Number(health.max??1)}></progress><span>{badge(unit)} · HP {String(health.cur)}/{String(health.max)}</span></div>{/if}{/each}</div>
              {#if combatStage}<div class="intervention"><b>📣 지휘 개입 예약</b><select bind:value={interventionType} disabled={Number(sortie.command)<100}><option value="">사용 안 함</option><option value="focus">집중사격</option><option value="brace">긴급 엄폐</option><option value="barrage">탄막 요청</option></select><select bind:value={interventionRound} disabled={!interventionType}>{#each [1,2,3,4,5,6,7,8] as round}<option value={round}>{round}라운드</option>{/each}</select><small>게이지 100을 소모해 한 라운드에 예약 적용합니다. 위험도 추정에는 포함되지 않습니다.</small></div>{/if}
              {#if !combatStage}<button class="stage-next" onclick={()=>act('gfl/sortie/stage',{},'narrated')}>단계 진행 · {String(({recon:'정찰',other:'돌발 상황',mystery:'미확인'}as Row)[String(currentStage.type)]??currentStage.type)}</button>
              {:else if sortie.engagementMode==='quick'}<button onclick={()=>act('gfl/sortie/engage',engageParams('balanced'),'narrated')}>교전 진행 · {current+1}/{stages.length}</button>
              {:else}<p>전술을 하나 선택하면 현재 교전의 명중·피해·생존 결과가 계산됩니다.</p><div class="tactics"><button onclick={()=>act('gfl/sortie/engage',engageParams('focus'),'narrated')}>집중 사격 <small>명중 우선</small></button><button onclick={()=>act('gfl/sortie/engage',engageParams('balanced'),'narrated')}>균형 전술 <small>표준</small></button><button onclick={()=>act('gfl/sortie/engage',engageParams('cover'),'narrated')}>엄폐 전진 <small>피해 억제</small></button></div>{/if}
              <button class="retreat" onclick={()=>act('gfl/sortie/retreat')}>작전 퇴각 · 획득 전리품 보존</button>
            </div>
          {:else if !selectedTheater}<p class="section-guide">먼저 전선을 선택하세요. 작전 지역은 같은 전선의 이전 지역을 클리어하면 순서대로 개방됩니다.</p><div class="theater-grid">{#each theaterRows as theater}<button onclick={()=>{selectedTheater=String(theater.id);selectedMission='';}}><b>{String(theater.name)}</b><small>{String(theater.description??'')}</small><span>{missions.filter(value=>theater.id==='all'||value.theater===theater.id).length}개 지역</span></button>{/each}</div>
          {:else}<button class="back" onclick={()=>{selectedTheater='';selectedMission='';}}>← 전선 다시 선택</button><div class="mission-grid">{#each theaterMissions as operation}<button class:selected={selectedMission===operation.id} class:locked={!operation.unlocked} disabled={!operation.unlocked} onclick={()=>selectedMission=String(operation.id)}><b>{operation.unlocked?'':'🔒 '}{String(operation.name)} {operation.completed?'✓':''} {operation.boss?'👑':''}</b><small>{String(operation.difficulty)} · 요구 {String(operation.power)}{#if operation.travelCost} · 이동비 {String(operation.travelCost)}{/if}</small><span>{#if operation.unlocked}{#each (Array.isArray(operation.factions)?operation.factions:[]) as faction}<em class="faction">{String(factionBadges[String(faction)]??'')} {String(faction)}</em>{/each}{String(operation.enemy)}{:else}이전 작전 지역 클리어 필요{/if}</span></button>{/each}</div>
            <div class="mission-types" aria-label="임무 유형">{#each missionTypes as type}<button class:active={selectedMissionType===type.key} onclick={()=>selectedMissionType=String(type.key)}><b>{String(type.name)}</b><small>{String(type.hint)}</small></button>{/each}</div>
            <div class="deploy"><select bind:value={selectedEchelon}>{#each echelons as entry}<option value={entry.id}>{String(entry.name)} · {String(entry.power)}</option>{/each}</select>{#if selectedOperation}{@const estimate=risk(selectedOperation,activeEchelon)}<div class:risk-high={estimate.chance<60} class="risk"><b>{estimate.label} · 성공 가능성 약 {estimate.chance}%</b><span>제대 {estimate.power} / 요구 {estimate.required} · d20 보정 {estimate.modifier>=0?'+':''}{estimate.modifier}</span>{#if estimate.commanderBonus>0}<span class="commander-bonus">지휘 보정 +{estimate.commanderBonus}</span>{/if}{#if selectedOperation.counterLabel}<span class="counter-line">상성: {String(selectedOperation.counterLabel)} · 제대 내 유리 병과 {activeSlots.filter(member=>{const unit=dolls.find(value=>value.id===slotId(member));return Array.isArray(selectedOperation.advantagedClasses)&&selectedOperation.advantagedClasses.includes(unit?.class)}).length}명</span>{/if}<small>전투력이 낮아도 출격할 수 있지만 실패·부상 위험이 커집니다.</small></div>{/if}<button disabled={!selectedMission||daily.sortiesRemaining<=0} onclick={()=>act('gfl/sortie/start',{missionId:selectedMission,echelonId:selectedEchelon,missionType:selectedMissionType,command:'remote',engagementMode:'quick'})}>빠른 교전</button><button disabled={!selectedMission||daily.sortiesRemaining<=0} onclick={()=>act('gfl/sortie/start',{missionId:selectedMission,echelonId:selectedEchelon,missionType:selectedMissionType,command:'field',engagementMode:'tactical'})}>전술 교전</button></div>{/if}
        </section>
      {:else if tab==='factory'}
        <section class="list"><h2>제조·수복 대기열</h2><div class="factory-actions"><button onclick={()=>act('gfl/manufacture/start',{kind:'doll'})}>인형 제조</button><button onclick={()=>act('gfl/manufacture/start',{kind:'equipment'})}>장비 제조</button><button onclick={()=>act('gfl/manufacture/start',{kind:'doll',heavy:true})}>중형 제조</button></div><h3>제조</h3>{#each queues.manufacturing as job}<article><span>{String(job.kind)} · {String(job.status)}</span><b>{String(job.remaining)}단계</b>{#if job.status==='active'}<button onclick={()=>act('gfl/manufacture/tick',{jobId:job.id})}>시간 진행</button>{/if}</article>{/each}<h3>수복</h3>{#each queues.repairs as job}<article><span>{String(dolls.find(value=>value.id===job.dollId)?.name??job.dollId)} · {String(job.status)}</span><b>{String(job.remaining)}단계</b>{#if job.status==='active'}<button onclick={()=>act('gfl/repair/tick',{jobId:job.id})}>시간 진행</button>{/if}</article>{/each}</section>
        {#if queues.repairs.some(job=>job.status==='active')}<section class="rush-repair"><b>긴급 수복</b><span>추가 부품 2개로 즉시 완료하며 주사위는 굴리지 않습니다.</span>{#each queues.repairs.filter(job=>job.status==='active') as job}<button onclick={()=>act('gfl/repair/rush',{jobId:job.id})}>{String(dolls.find(value=>value.id===job.dollId)?.name??job.dollId)} 즉시 수복</button>{/each}</section>{/if}
      {:else}
        {#if shopMode==='inventory'}<section class="scrap"><h3>장비 해체</h3>{#each shop.catalog.filter(item=>item.kind==='equipment'&&Number(item.owned??0)>0) as item}<article><b>{String(item.name)} · 보유 {String(item.owned)}</b><button onclick={()=>{if(confirm(`${String(item.name)} 장비를 해체하시겠습니까?`))act('gfl/equipment/scrap',{equipmentId:item.id,confirm:true})}}>해체 · 부품 {Math.floor(Number(item.price??0)*.3)}</button></article>{/each}</section>{/if}
        <section class="list"><h2>상점·장비</h2>{#if shopMode==='menu'}<p class="section-guide">필요한 시설을 선택하면 상품 이미지·효과·사용법·가격을 한 카드에서 확인할 수 있습니다.</p><div class="theater-grid"><button onclick={()=>shopMode='supply'}><b>카리나 보급 상점</b><small>소모품과 보급 물자를 구매합니다.</small></button><button onclick={()=>shopMode='equipment'}><b>장비 상점</b><small>전술인형용 장비를 구매합니다.</small></button><button onclick={()=>shopMode='inventory'}><b>보관함·장비 관리</b><small>보유 물품을 확인하고 인형에게 장착합니다.</small></button><button onclick={()=>shopMode='fairy'}><b>전술요정</b><small>요정을 계약하고 제대에 배치합니다.</small></button></div>{:else}<button class="back" onclick={()=>shopMode='menu'}>← 상점·장비 분류로</button>{#if shopMode==='supply'}<h3>카리나 보급 상점</h3><div class="shop-grid">{#each shop.catalog.filter(item=>item.kind==='item') as item}<GflShopCard {item} image={asset(String(item.asset??item.name))} funds={Number(status.funds??0)} {busy} onbuy={()=>act('gfl/shop/buy',{itemId:item.id})}/>{/each}</div>{:else if shopMode==='equipment'}<h3>장비 상점</h3><div class="shop-grid">{#each shop.catalog.filter(item=>item.kind==='equipment') as item}<GflShopCard {item} image={asset(String(item.asset??item.name))} funds={Number(status.funds??0)} {busy} onbuy={()=>act('gfl/shop/buy',{itemId:item.id})}/>{/each}</div>{:else if shopMode==='inventory'}<h3>보관함·장비 관리</h3><div class="shop-grid">{#each shop.catalog.filter(item=>Number(item.owned??0)>0) as item}<article><div><b>{String(item.name)}</b><small>{String(item.kind)} · 보유 {String(item.owned)}</small></div>{#if item.kind==='equipment'&&activeDoll}<button onclick={()=>act('gfl/equipment/equip',{dollId:activeDoll.id,equipmentId:item.id})}>{String(activeDoll.name)} 장착</button>{/if}</article>{/each}</div>{:else}<h3>전술요정</h3><div class="shop-grid">{#each shop.fairyCatalog as fairy}<article><div><b>{String(fairy.name)}</b><small>{shop.fairies.some(value=>value.id===fairy.id)?'계약 완료':'미계약'}</small></div>{#if !shop.fairies.some(value=>value.id===fairy.id)}<button onclick={()=>act('gfl/fairy/acquire',{fairyId:fairy.id})}>계약</button>{:else if activeEchelon}<button onclick={()=>act('gfl/fairy/assign',{fairyId:fairy.id,echelonId:activeEchelon.id})}>{String(activeEchelon.name)} 배치</button>{/if}</article>{/each}</div>{/if}{/if}</section>
      {/if}
    </div>
  {/if}
</div>

<style>
  .gfl{--amber:#e5a84b;--cyan:#7cc8d8;min-height:32rem;border:1px solid #424a4d;background:linear-gradient(145deg,#141a1d,#090d0f);color:#d9e1df;font:13px/1.45 ui-monospace,'Noto Sans KR',sans-serif;overflow:hidden}.status{display:grid;grid-template-columns:repeat(6,1fr);border-bottom:1px solid #4b5554;background:#101719}.status div{display:grid;gap:2px;padding:8px 12px;border-right:1px solid #303a3a}.status span{font-size:9px;color:#7f9290;letter-spacing:.12em}.status b{color:var(--amber)}.mobile-status{display:none}.boot{display:grid;place-items:center;min-height:28rem;padding:28px;text-align:center;background:radial-gradient(circle at 50% 30%,#263439 0,transparent 50%)}.boot h2{margin:0;color:var(--amber);font-size:28px;letter-spacing:.08em}.boot p{max-width:50ch;color:#9dacaa}.boot .code{color:var(--cyan);font-size:10px;letter-spacing:.2em}.boot div,.factory-actions,.deploy,.echelon-tabs{display:flex;gap:8px;flex-wrap:wrap}button,select{padding:8px 11px;border:1px solid #475353;border-radius:2px;background:#172024;color:#dce5e3}button:hover,button.active,button.selected{border-color:var(--amber);color:#ffd78e;background:#24251f}button:disabled{opacity:.4}nav{display:flex;border-bottom:1px solid #35403f;background:#111719}nav button{flex:1;border-width:0 1px 0 0;border-radius:0}.workspace{display:grid;grid-template-columns:minmax(0,1.25fr) minmax(18rem,.75fr);min-height:28rem}.stage{position:relative;min-height:28rem;overflow:hidden;background:radial-gradient(circle at 50% 55%,#354344,#121819 65%)}.stage img{position:absolute;inset:0;width:100%;height:100%;object-fit:contain;object-position:center bottom}.scan{position:absolute;inset:0;background:repeating-linear-gradient(0deg,transparent 0 3px,#8fd1d508 4px)}.name{position:absolute;left:18px;bottom:16px;padding:5px 10px;border-left:3px solid var(--amber);background:#080c0dcc;color:#fff;font-weight:700}.dialogue,.detail,.list{padding:16px}.dialogue{display:grid;align-content:end;gap:12px;border-left:1px solid #36403f;background:#0d1214}.dialogue>span{color:var(--cyan);font-size:10px}.dialogue>p{min-height:5rem;padding:12px;border:1px solid #3c4645;background:#151d1f}.facility-grid,.mission-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:8px}.facility-grid article{display:block;margin:0;padding:0}.facility-summary,.mission-grid button{display:grid;gap:4px;width:100%;text-align:left}.facility-summary span{justify-self:start;padding:2px 5px;border:1px solid #53766f;color:#9ed7c9;font-size:9px}.facility-detail{display:grid;gap:4px;padding:8px}.facility-grid small,.mission-grid small,.shop-grid small,.hire-grid small{color:#8fa09d}.list{grid-column:1/-1;overflow:auto}.detail{border-left:1px solid #35403f;background:#0d1214}.detail label{display:grid;gap:4px}.detail progress{width:100%;accent-color:var(--amber)}.slots{display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin:16px 0}.slots button{display:grid;min-height:90px;align-content:center}.slots span{font-size:9px;color:#72827f}.slot.recommended{outline:2px solid var(--cyan);outline-offset:2px}.mission-grid button span{font-size:11px;color:#a8b3b0}.faction{display:inline-block;margin-right:4px;padding:1px 4px;border:1px solid #536866;color:var(--cyan);font-style:normal}.brief{display:grid;gap:8px;padding:14px;border:1px solid var(--amber);background:#262218}.deploy{margin-top:12px}.deploy select{min-width:12rem}.list article{display:grid;grid-template-columns:1fr auto auto;align-items:center;gap:8px;margin:6px 0;padding:9px;border:1px solid #333e3d;background:#12191b}.shop-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:8px}.shop-grid article{grid-template-columns:minmax(0,1fr) auto auto}.shop-grid article div{display:grid}.hire-head{display:flex;align-items:center;justify-content:space-between;gap:12px}.hire-head h2,.hire-head p{margin:0}.hire-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:8px;margin:14px 0}.hire-grid article{grid-template-columns:70px minmax(0,1fr);align-items:start}.hire-grid .portrait{grid-row:1/3;width:70px;height:100px;overflow:hidden;background:#0b1012}.hire-grid img{width:100%;height:100%;object-fit:cover;object-position:top}.portrait-loading{display:grid;width:100%;height:100%;place-items:center;padding:4px;color:#71817e;font-size:10px;text-align:center}.hire-grid p{margin:5px 0;color:#9ba9a6}.hire-grid strong,.hire-grid button{grid-column:2}
  .location-bar{display:flex;align-items:center;gap:10px;padding:7px 10px;border-bottom:1px solid #303a3a;background:#0d1315}.location-bar>span{flex:0 0 auto;color:#8fa09d}.location-bar b{color:var(--cyan)}.location-bar>div{display:flex;gap:5px;overflow-x:auto}.location-bar button{flex:0 0 auto;padding:5px 8px;font-size:11px}
  .section-guide{max-width:62ch;color:#9ba9a6}.theater-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(210px,1fr));gap:10px}.theater-grid button{display:grid;gap:6px;min-height:100px;text-align:left;align-content:center}.theater-grid small{color:#8fa09d}.theater-grid span{color:var(--cyan);font-size:11px}.back{margin-bottom:12px;border-color:#60706f;color:var(--cyan)}
